    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let actionsStatus =
        (Option.map ~f:AutoRepairActionsStatus.of_xml)
          (Xml.child xml_arg0 "actionsStatus") in
      make ?actionsStatus ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let actionsStatus =
        field_map json__ "actionsStatus" AutoRepairActionsStatus.of_json in
      make ?actionsStatus ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc
       "The auto repair configuration for an Amazon ECS Managed Instances capacity provider. When enabled, Amazon ECS automatically replaces container instances that are detected as unhealthy based on container instance health checks, including accelerated compute device and daemon health checks."]
module InfrastructureOptimization =
