module InstanceLaunchTemplate =
  struct
    type nonrec t =
      {
      ec2InstanceProfileArn: String_.t
        [@ocaml.doc
          "The Amazon Resource Name (ARN) of the instance profile that Amazon ECS applies to Amazon ECS Managed Instances. This instance profile must include the necessary permissions for your tasks to access Amazon Web Services services and resources. For more information, see Amazon ECS instance profile for Managed Instances in the Amazon ECS Developer Guide."];
      networkConfiguration: ManagedInstancesNetworkConfiguration.t
        [@ocaml.doc
          "The network configuration for Amazon ECS Managed Instances. This specifies the subnets and security groups that instances use for network connectivity."];
      storageConfiguration: ManagedInstancesStorageConfiguration.t option
        [@ocaml.doc
          "The storage configuration for Amazon ECS Managed Instances. This defines the data volume properties for the instances."];
      localStorageConfiguration:
        ManagedInstancesLocalStorageConfiguration.t option
        [@ocaml.doc
          "The local storage configuration for Amazon ECS Managed Instances. This defines how ECS uses instance store volumes available on the container instance."];
      monitoring: ManagedInstancesMonitoringOptions.t option
        [@ocaml.doc
          "CloudWatch provides two categories of monitoring: basic monitoring and detailed monitoring. By default, your managed instance is configured for basic monitoring. You can optionally enable detailed monitoring to help you more quickly identify and act on operational issues. You can enable or turn off detailed monitoring at launch or when the managed instance is running or stopped. For more information, see Detailed monitoring for Amazon ECS Managed Instances in the Amazon ECS Developer Guide."];
      capacityOptionType: CapacityOptionType.t option
        [@ocaml.doc
          "The capacity option type. This determines whether Amazon ECS launches On-Demand, Spot or Capacity Reservation Instances for your managed instance capacity provider. Valid values are: ON_DEMAND - Launches standard On-Demand Instances. On-Demand Instances provide predictable pricing and availability. SPOT - Launches Spot Instances that use spare Amazon EC2 capacity at reduced cost. Spot Instances can be interrupted by Amazon EC2 with a two-minute notification when the capacity is needed back. RESERVED - Launches Instances using Amazon EC2 Capacity Reservations. Capacity Reservations allow you to reserve compute capacity for Amazon EC2 instances in a specific Availability Zone. The default is On-Demand For more information about Amazon EC2 capacity options, see Instance purchasing options in the Amazon EC2 User Guide."];
      instanceMetadataTagsPropagation: BoxedBoolean.t option
        [@ocaml.doc
          "Determines whether tags are propagated to the instance metadata service (IMDS) for Amazon EC2 instances launched by the Managed Instances capacity provider. When enabled, all tags associated with the instance are available through the instance metadata service. When disabled, tags are not propagated to IMDS. Disable this setting if your tags contain characters that are not compatible with IMDS, such as /. IMDS requires tag keys to match the pattern \\[0-9a-zA-Z\\-_+=,.\\@:\\]\\{1,255\\}. The default value is true. For more information, see Work with instance tags in instance metadata in the Amazon EC2 User Guide."];
      instanceRequirements: InstanceRequirementsRequest.t option
        [@ocaml.doc
          "The instance requirements. You can specify: The instance types Instance requirements such as vCPU count, memory, network performance, and accelerator specifications Amazon ECS automatically selects the instances that match the specified criteria."];
      fipsEnabled: BoxedBoolean.t option
        [@ocaml.doc
          "Determines whether to enable FIPS 140-2 validated cryptographic modules on EC2 instances launched by the capacity provider. If true, instances use FIPS-compliant cryptographic algorithms and modules for enhanced security compliance. If false, instances use standard cryptographic implementations. If not specified, instances are launched with FIPS enabled in Amazon Web Services GovCloud (US) regions and FIPS disabled in other regions."];
      capacityReservations: CapacityReservationRequest.t option
        [@ocaml.doc
          "Capacity reservation specifications. You can specify: Capacity reservation preference Reservation resource group to be used for targeted capacity reservations Amazon ECS will launch instances according to the specified criteria."]}
    let context_ = "InstanceLaunchTemplate"
    let make ?storageConfiguration =
      fun ?localStorageConfiguration ->
        fun ?monitoring ->
          fun ?capacityOptionType ->
            fun ?instanceMetadataTagsPropagation ->
              fun ?instanceRequirements ->
                fun ?fipsEnabled ->
                  fun ?capacityReservations ->
                    fun ~ec2InstanceProfileArn ->
                      fun ~networkConfiguration ->
                        fun () ->
                          {
                            storageConfiguration;
                            localStorageConfiguration;
                            monitoring;
                            capacityOptionType;
                            instanceMetadataTagsPropagation;
                            instanceRequirements;
                            fipsEnabled;
                            capacityReservations;
                            ec2InstanceProfileArn;
                            networkConfiguration
                          }
    let to_value x =
      structure_to_value
        [("ec2InstanceProfileArn",
           (Some (String_.to_value x.ec2InstanceProfileArn)));
        ("networkConfiguration",
          (Some
             (ManagedInstancesNetworkConfiguration.to_value
                x.networkConfiguration)));
        ("storageConfiguration",
          (Option.map x.storageConfiguration
             ~f:ManagedInstancesStorageConfiguration.to_value));
        ("localStorageConfiguration",
          (Option.map x.localStorageConfiguration
             ~f:ManagedInstancesLocalStorageConfiguration.to_value));
        ("monitoring",
          (Option.map x.monitoring
             ~f:ManagedInstancesMonitoringOptions.to_value));
        ("capacityOptionType",
          (Option.map x.capacityOptionType ~f:CapacityOptionType.to_value));
        ("instanceMetadataTagsPropagation",
          (Option.map x.instanceMetadataTagsPropagation
             ~f:BoxedBoolean.to_value));
        ("instanceRequirements",
          (Option.map x.instanceRequirements
             ~f:InstanceRequirementsRequest.to_value));
        ("fipsEnabled", (Option.map x.fipsEnabled ~f:BoxedBoolean.to_value));
        ("capacityReservations",
          (Option.map x.capacityReservations
             ~f:CapacityReservationRequest.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let capacityReservations =
        (Option.map ~f:CapacityReservationRequest.of_xml)
          (Xml.child xml_arg0 "capacityReservations") in
      let fipsEnabled =
        (Option.map ~f:BoxedBoolean.of_xml)
          (Xml.child xml_arg0 "fipsEnabled") in
      let instanceRequirements =
        (Option.map ~f:InstanceRequirementsRequest.of_xml)
          (Xml.child xml_arg0 "instanceRequirements") in
      let instanceMetadataTagsPropagation =
        (Option.map ~f:BoxedBoolean.of_xml)
          (Xml.child xml_arg0 "instanceMetadataTagsPropagation") in
      let capacityOptionType =
        (Option.map ~f:CapacityOptionType.of_xml)
          (Xml.child xml_arg0 "capacityOptionType") in
      let monitoring =
        (Option.map ~f:ManagedInstancesMonitoringOptions.of_xml)
          (Xml.child xml_arg0 "monitoring") in
      let localStorageConfiguration =
        (Option.map ~f:ManagedInstancesLocalStorageConfiguration.of_xml)
          (Xml.child xml_arg0 "localStorageConfiguration") in
      let storageConfiguration =
        (Option.map ~f:ManagedInstancesStorageConfiguration.of_xml)
          (Xml.child xml_arg0 "storageConfiguration") in
      let networkConfiguration =
        ManagedInstancesNetworkConfiguration.of_xml
          (Xml.child_exn ~context:context_ xml_arg0 "networkConfiguration") in
      let ec2InstanceProfileArn =
        String_.of_xml
          (Xml.child_exn ~context:context_ xml_arg0 "ec2InstanceProfileArn") in
      make ?capacityReservations ?fipsEnabled ?instanceRequirements
        ?instanceMetadataTagsPropagation ?capacityOptionType ?monitoring
        ?localStorageConfiguration ?storageConfiguration
        ~networkConfiguration ~ec2InstanceProfileArn ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let capacityReservations =
        field_map json__ "capacityReservations"
          CapacityReservationRequest.of_json in
      let fipsEnabled = field_map json__ "fipsEnabled" BoxedBoolean.of_json in
      let instanceRequirements =
        field_map json__ "instanceRequirements"
          InstanceRequirementsRequest.of_json in
      let instanceMetadataTagsPropagation =
        field_map json__ "instanceMetadataTagsPropagation"
          BoxedBoolean.of_json in
      let capacityOptionType =
        field_map json__ "capacityOptionType" CapacityOptionType.of_json in
      let monitoring =
        field_map json__ "monitoring"
          ManagedInstancesMonitoringOptions.of_json in
      let localStorageConfiguration =
        field_map json__ "localStorageConfiguration"
          ManagedInstancesLocalStorageConfiguration.of_json in
      let storageConfiguration =
        field_map json__ "storageConfiguration"
          ManagedInstancesStorageConfiguration.of_json in
      let networkConfiguration =
        field_map_exn json__ "networkConfiguration"
          ManagedInstancesNetworkConfiguration.of_json in
      let ec2InstanceProfileArn =
        field_map_exn json__ "ec2InstanceProfileArn" String_.of_json in
      make ?capacityReservations ?fipsEnabled ?instanceRequirements
        ?instanceMetadataTagsPropagation ?capacityOptionType ?monitoring
        ?localStorageConfiguration ?storageConfiguration
        ~networkConfiguration ~ec2InstanceProfileArn ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc
       "The launch template configuration for Amazon ECS Managed Instances. This defines how Amazon ECS launches Amazon EC2 instances, including the instance profile for your tasks, network and storage configuration, capacity options, and instance requirements for flexible instance type selection."]
